```c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <sys/socket.h>
#include <arpa/inet.h>
#include <pthread.h>

#define THREAD_COUNT 4   // 线程数
#define SERVER_PORT 9000 // 服务器端口号
#define BUFFER_SIZE 1024 // 缓存大小

pthread_t threads[THREAD_COUNT];
pthread_mutex_t mutex;

// 线程函数，向指定的IP地址发送UDP数据包
void *thread_func(void *arg)
{
    int sockfd;
    struct sockaddr_in server_addr;
    char buffer[BUFFER_SIZE];
    int length;
    int ret;

    // 初始化服务端地址
    memset(&server_addr, 0, sizeof(struct sockaddr_in));
    server_addr.sin_family = AF_INET;
    server_addr.sin_addr.s_addr = inet_addr((char *)arg);
    server_addr.sin_port = htons(SERVER_PORT);

    // 创建UDP Socket
    sockfd = socket(AF_INET, SOCK_DGRAM, 0);
    if (sockfd < 0) {
        perror("socket error");
        exit(-1);
    }

    // 发送UDP数据包
    while (1) {
        length = sprintf(buffer, "Hello from thread %lu", pthread_self());
        ret = sendto(sockfd, buffer, length, 0, (struct sockaddr *)&server_addr, sizeof(struct sockaddr_in));
        if (ret < 0) {
            perror("sendto error");
            exit(-1);
        }
        printf("Thread %lu sent packet to %s\n", pthread_self(), (char *)arg);
        sleep(2);
    }

    pthread_exit(NULL);
}

int main(int argc, char *argv[])
{
    int sockfd;
    struct sockaddr_un servaddr;
    char buffer[BUFFER_SIZE];
    int length;
    int ret;
    int i;

    if (argc < 2) {
        printf("Usage: %s IP1 IP2 IP3 IP4 ...\n", argv[0]);
        exit(-1);
    }

    // 创建UNIX Domain Socket
    sockfd = socket(AF_UNIX, SOCK_STREAM, 0);
    if (sockfd < 0) {
        perror("socket error");
        exit(-1);
    }

    // 初始化服务器地址
    memset(&servaddr, 0, sizeof(struct sockaddr_un));
    servaddr.sun_family = AF_UNIX;
    strcpy(servaddr.sun_path, "server.sock");

    // 绑定UNIX Domain Socket
    ret = bind(sockfd, (struct sockaddr *)&servaddr, SUN_LEN(&servaddr));
    if (ret < 0) {
        perror("bind error");
        exit(-1);
    }

    // 启动线程
    for (i = 0; i < THREAD_COUNT; i++) {
        ret = pthread_create(&threads[i], NULL, thread_func, argv[i + 1]);
        if (ret != 0) {
            printf("pthread_create error: %s\n", strerror(ret));
            exit(-1);
        }
    }

    // 等待线程结束
    for (i = 0; i < THREAD_COUNT; i++) {
        pthread_join(threads[i], NULL);
    }

    // 关闭UNIX Domain Socket
    close(sockfd);

    return 0;
}
```

在这个例子中，我们使用了一个大小为THREAD_COUNT的线程数组，并通过遍历这个数组来创建线程。每个线程都执行thread_func函数，该函数通过输入参数获取要发送UDP数据包的目标IP地址，并且使用sendto函数来发送数据包。

同时，我们使用了一个简单的Unix域套接字（UNIX domain socket）来让线程之间进行通信。这种方式可以让主进程和子线程之间更容易地交换信息，并且避免使用复杂的IPC机制。

这只是一个简单的例子，你可以根据实际需要进行修改和扩展。

