#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <sys/socket.h>
#include <arpa/inet.h>

#define SERVER_PORT 9000 // 服务器端口号
#define BUFFER_SIZE 1024 // 缓存大小

int main(int argc, char *argv[])
{
    int sockfd;
    struct sockaddr_in server_addr;
    char buffer[BUFFER_SIZE];
    int length;
    int ret;

    if (argc < 2) {
        printf("Usage: %s server_ip\n", argv[0]);
        exit(-1);
    }

    // 初始化服务端地址
    memset(&server_addr, 0, sizeof(struct sockaddr_in));
    server_addr.sin_family = AF_INET;
    server_addr.sin_addr.s_addr = inet_addr(argv[1]);
    server_addr.sin_port = htons(SERVER_PORT);

    // 创建UDP Socket
    sockfd = socket(AF_INET, SOCK_DGRAM, 0);
    if (sockfd < 0) {
        perror("socket error");
        exit(-1);
    }

    // 发送UDP数据包
    while (1) {
        printf("Input message: ");
        fgets(buffer, BUFFER_SIZE, stdin); // 从终端读取输入数据
        length = strlen(buffer) - 1;
        ret = sendto(sockfd, buffer, length, 0, (struct sockaddr *)&server_addr, sizeof(struct sockaddr_in));
        if (ret < 0) {
            perror("sendto error");
            exit(-1);
        }
        printf("Sent packet to server\n");
    }

    // 关闭UDP Socket
    close(sockfd);

    return 0;
}
